function StructItem:CreateByPb(pb)
	self._refId = pb.refId
	self._num = pb.num
	self._state = pb.state

	self._itemExtras = {}
	local itemExtras = pb.itemExtras

	self._extraDataMap = {}
	for i,v in ipairs(itemExtras) do
