		end
		local data = {
			id = v.id,
			refId = v.refId,
			type = v.type,
			createTime = tonumber(v.createTime),
			rewardDays = day,
			rewardDaysKey = dayKey,
			extra = v.extra
		}
		table.insert(self._itemExtras,data)

		self._extraDataMap[data.id] = data


	end
end

function StructItem:GetCreateTime()
	local createTime = 0
	for k, v in ipairs(self._itemExtras) do
		if v.createTime > createTime then
			createTime = v.createTime
		end
	end
	return createTime
end

